/**
 * Byron Bay Candles — Client-specific hooks.
 *
 * Loaded via manifest.json when this client is active.
 * These hooks are specific to BBC and should NOT be in the shared theme.
 *
 * @package Blocksy_Child
 * @client  Byron Bay Candles
 */

if ( ! defined( 'ABSPATH' ) ) {
	exit;
}

/**
 * Rename "Related Products" heading to "You May Also Like".
 *
 * WHY: Client-preferred label per ClickUp task. Not a universal pattern.
 * @date 2026-03-17
 */
add_filter( 'gettext', function ( $translated, $text, $domain ) {
	if ( 'woocommerce' === $domain && 'Related products' === $text ) {
		return 'You May Also Like';
	}
	return $translated;
}, 10, 3 );

/**
 * Display Google Reviews (Business Reviews Bundle) after product tabs.
 *
 * WHY: BBC wants Google reviews on every product page.
 * Collection ID 58908 is BBC's Google reviews collection.
 * @date 2026-03-17
 */
add_action( 'woocommerce_after_single_product_summary', function () {
	if ( shortcode_exists( 'brb_collection' ) ) {
		echo '<div class="bc-reviews-bundle">';
		echo do_shortcode( '[brb_collection id="58908"]' );
		echo '</div>';
	}
}, 25 );

