/**
 * Blocksy version sentinel — detects when Blocksy or Blocksy Companion Pro
 * is updated, logs to error_log, and queues an admin notice prompting QA
 * of dependent UI (wishlist drawer suggested products, mini cart empty state,
 * any other Blocksy-flexy-dependent rendering).
 *
 * WHY: 2026-04-26 incident — Blocksy 2.1.37 → 2.1.38 changed flexy.min.css
 * to translate items -100% off-screen as the un-init state. This silently
 * broke the wishlist drawer's suggested products carousel because flexy JS
 * doesn't initialize inside our custom panel. Visible regression but no
 * error path. This sentinel ensures the next time it happens we know.
 *
 * @date 2026-04-26
 */
add_action( 'admin_init', function () {
	if ( ! function_exists( 'wp_get_theme' ) ) {
		return;
	}

	$blocksy_v        = wp_get_theme( 'blocksy' )->get( 'Version' );
	$blocksy_pro_v    = '';
	if ( defined( 'BLOCKSY_COMPANION_VERSION' ) ) {
		$blocksy_pro_v = BLOCKSY_COMPANION_VERSION;
	} elseif ( function_exists( 'get_plugin_data' ) ) {
		$pro_path = WP_PLUGIN_DIR . '/blocksy-companion-pro/blocksy-companion-pro.php';
		if ( file_exists( $pro_path ) ) {
			$pro_data = get_plugin_data( $pro_path, false, false );
			$blocksy_pro_v = isset( $pro_data['Version'] ) ? $pro_data['Version'] : '';
		}
	}

	$current_signature = $blocksy_v . '|' . $blocksy_pro_v;
	$known_signature   = get_option( 'bbc_blocksy_version_signature', '' );

	if ( $current_signature === $known_signature ) {
		return;
	}

	error_log(
		sprintf(
			'[BBC sentinel] Blocksy stack version changed (theme: %s, pro: %s — was: %s). '
			. 'Verify wishlist drawer suggested-products + mini-cart empty state still render correctly. '
			. 'See clients/byronbay/byronbay.php for context.',
			$blocksy_v,
			$blocksy_pro_v,
			$known_signature ?: '(first run)'
		)
	);

	update_option( 'bbc_blocksy_version_signature', $current_signature, false );

	// Admin notice (one-shot) — only shown once per signature change.
	set_transient( 'bbc_blocksy_version_changed_notice', $current_signature, DAY_IN_SECONDS );
} );

add_action( 'admin_notices', function () {
	$sig = get_transient( 'bbc_blocksy_version_changed_notice' );
	if ( ! $sig ) {
		return;
	}
	if ( ! current_user_can( 'manage_options' ) ) {
		return;
	}
	echo '<div class="notice notice-warning is-dismissible">';
	echo '<p><strong>Blocksy version changed.</strong> ';
	echo 'Verify the off-canvas wishlist drawer still shows the Suggested Products carousel and the mini-cart empty state still shows Recently Viewed + Favourites. ';
	echo 'If broken, check <code>assets/css/components/wishlist-offcanvas.css</code> for flexy overrides — Blocksy may have changed its flexy CSS again. ';
	echo '<em>(Signature: ' . esc_html( $sig ) . ')</em></p>';
	echo '</div>';
} );


/**
 * Gift card PDP — remove duplicate PAO "Message" group and fix field order.
 *
 * WHY 1: Global add-on group 635743 ("Gift Voucher") adds a custom_textarea
 * that duplicates PWGC's own Message field. Filter it out site-wide via
 * get_product_addons_fields so no DB change is needed.
 *
 * WHY 2: PAO's reposition_display_for_variable_product() (fired at
 * woocommerce_before_variations_form p10) moves Gift-wrap to
 * woocommerce_single_variation p15 — which renders BEFORE the
 * woocommerce-variation-add-to-cart div (where PWGC fields live).
 * Counter it at p11: remove PAO from single_variation p15, re-add to
 * woocommerce_before_add_to_cart_quantity p1 so it renders INSIDE the
 * form, after the PWGC fields (PWGC fires at woocommerce_before_add_to_cart_button p30).
 *
 * @date 2026-05-05
 */
add_filter( 'get_product_addons_fields', function ( $fields, $global_addon_id ) {
	if ( 635743 === (int) $global_addon_id ) {
		return array();
	}
	return $fields;
}, 10, 2 );

add_action( 'woocommerce_before_variations_form', function () {
	global $product;
	if ( ! is_a( $product, 'WC_Product_PW_Gift_Card' ) ) {
		return;
	}
	if ( ! isset( $GLOBALS['Product_Addon_Display'] ) ) {
		return;
	}
	$display = $GLOBALS['Product_Addon_Display'];
	remove_action( 'woocommerce_single_variation', array( $display, 'display' ), 15 );
	add_action( 'woocommerce_before_add_to_cart_quantity', array( $display, 'display' ), 1 );
}, 11 );
